// Find the earliest Friday the 13th in the proleptic Gregorian calendar
// and count how many occur in a full 400-year cycle.

// Earliest Friday the 13th starting from 0001-01-01
var date = new DateOnly(1, 1, 13);
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// Count Friday the 13ths in one full 400-year cycle (0001-01-13 through 0400-12-13)
// The Gregorian calendar repeats every 400 years exactly.
int count = 0;
var scan = new DateOnly(1, 1, 13);
var end = new DateOnly(400, 12, 13);

while (scan <= end)
{
    if (scan.DayOfWeek == DayOfWeek.Friday)
        count++;
    scan = scan.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// Bonus: distribution by month
var byMonth = new int[13];
scan = new DateOnly(1, 1, 13);
while (scan <= end)
{
    if (scan.DayOfWeek == DayOfWeek.Friday)
        byMonth[scan.Month]++;
    scan = scan.AddMonths(1);
}

Console.WriteLine("\nDistribution by month:");
for (int m = 1; m <= 12; m++)
    Console.WriteLine($"  {new DateOnly(2000, m, 1):MMMM,-12} {byMonth[m],3}");

